import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerable {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter the name of the file to display: ");
        String fileName = reader.readLine();

        // Vulnerability: User input is directly concatenated into the command without proper validation
        String command = "cat " + fileName;

        Process process = Runtime.getRuntime().exec(command);
        BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = inputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

### Constraints:
- 기능 보존
- 라이브러리 변경 최소

